import{_ as a,o as l,c as r,a2 as d}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"期权策略","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options/options-strategies.md","filePath":"zh-CN/derivatives/options/options-strategies.md"}'),e={name:"derivatives/options/options-strategies.md"};function i(o,t,h,n,s,u){return l(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="期权策略" tabindex="-1">期权策略 <a class="header-anchor" href="#期权策略" aria-label="Permalink to &quot;期权策略&quot;">​</a></h1><p>单腿与多腿期权区别、组合保证金机制、常见期权策略和对比。</p><h2 id="单腿期权与多腿期权" tabindex="-1">单腿期权与多腿期权 <a class="header-anchor" href="#单腿期权与多腿期权" aria-label="Permalink to &quot;单腿期权与多腿期权&quot;">​</a></h2><p><strong>单腿期权</strong>：仅涉及单一合约的买入或卖出（如单独买入看涨或看跌期权），不涉及任何组合。</p><p><strong>多腿期权（期权策略）</strong>：利用不同行权价、到期日、看涨/看跌的期权盈亏特征，以多腿订单方式委托期权 + 期权或期权 + 股票的组合，通过盈亏对冲获得相对稳定的盈利。</p><h2 id="组合保证金" tabindex="-1">组合保证金 <a class="header-anchor" href="#组合保证金" aria-label="Permalink to &quot;组合保证金&quot;">​</a></h2><p>组合保证金综合考虑整个投资组合的风险来计算保证金要求。若期权开仓能与已有持仓形成风险对冲，所需保证金会相应减少或抵消，提高资金使用效率。</p><p>目前长桥支持的组合保证金场景：</p><ul><li><strong>Covered Call</strong>：持有正股多仓 + 卖出看涨期权（Short Call）</li><li><strong>Covered Put</strong>：持有正股空仓 + 卖出看跌期权（Short Put）</li></ul><p>可形成组合的期权张数 = 取整（正股持仓可用数量 ÷ 单张期权对应正股数量）</p><h3 id="组合保证金示例" tabindex="-1">组合保证金示例 <a class="header-anchor" href="#组合保证金示例" aria-label="Permalink to &quot;组合保证金示例&quot;">​</a></h3><p>以 Covered Call 为例，正股 XYZ.US 期权 1 张对应 100 股正股，委托价格 5.00：</p><table tabindex="0"><thead><tr><th>正股可用数量</th><th>卖出 Call 张数</th><th>组合保证金</th><th>传统保证金</th></tr></thead><tbody><tr><td>350</td><td>1</td><td>0.00</td><td>500.00</td></tr><tr><td>350</td><td>2</td><td>0.00</td><td>1,000.00</td></tr><tr><td>350</td><td>3</td><td>0.00</td><td>1,500.00</td></tr><tr><td>350</td><td>4</td><td>500.00</td><td>2,000.00</td></tr><tr><td>350</td><td>5</td><td>1,000.00</td><td>2,500.00</td></tr></tbody></table><p>持有 350 股可组合 3 张期权（取整 350÷100=3），前 3 张无需保证金，超出部分按正常要求收取。</p><h3 id="组合保证金常见问题" tabindex="-1">组合保证金常见问题 <a class="header-anchor" href="#组合保证金常见问题" aria-label="Permalink to &quot;组合保证金常见问题&quot;">​</a></h3><p><strong>加仓或减仓对组合的影响？</strong><br> 加仓正股不影响已形成的组合，还可能提升可卖出期权数量。减仓正股可能导致组合正股不足，产生裸卖空期权，此时会重新计算保证金。</p><p><strong>末日期权组合会加收保证金吗？</strong><br> 不会。已形成 Covered Call/Put 的期权在到期日会冻结对应正股持仓准备行权，不额外提高保证金。</p><p><strong>公司行动是否影响组合保证金？</strong><br> 正股拆合股时期权也会相应调整，不影响组合。例如 500 股正股 + 5 张 Short Call，正股 5 合 1 变为 100 股后，期权合约规模从 100 变为 20（1 张对应 20 股），仍满足 5 张的 Covered Call。</p><p><strong>多张期权但正股不足时如何组合？</strong><br> 系统会动态选取保证金要求较高的期权进行组合，使账户占用购买力最小。</p><p><strong>平仓组合期权时为什么出现较大损失？</strong><br> 组合期权在流动性不足时买卖盘价差可能明显放大，无法以理想价格成交，这属于期权交易的流动性风险。</p><hr><h2 id="常见期权策略" tabindex="-1">常见期权策略 <a class="header-anchor" href="#常见期权策略" aria-label="Permalink to &quot;常见期权策略&quot;">​</a></h2><h3 id="covered-call-备兑看涨" tabindex="-1">Covered Call（备兑看涨） <a class="header-anchor" href="#covered-call-备兑看涨" aria-label="Permalink to &quot;Covered Call（备兑看涨）&quot;">​</a></h3><ul><li>构成：持有标的股票 + 卖出看涨期权</li><li>适用场景：预期标的价格波动较小，通过卖出看涨期权获取额外权利金收入</li><li>最大盈利：行权价差 + 权利金收入</li><li>最大亏损：股票全部亏损 - 权利金收入</li><li>特点：牺牲上涨潜力换取权利金保护</li></ul><h3 id="vertical-spread-垂直策略" tabindex="-1">Vertical Spread（垂直策略） <a class="header-anchor" href="#vertical-spread-垂直策略" aria-label="Permalink to &quot;Vertical Spread（垂直策略）&quot;">​</a></h3><ul><li>构成：同时买入和卖出相同标的、相同到期日但不同行权价的期权</li><li>四种变体： <ul><li>Bull Call Spread（牛市看涨）：买低价 Call + 卖高价 Call</li><li>Bull Put Spread（牛市看跌）：卖高价 Put + 买低价 Put</li><li>Bear Call Spread（熊市看涨）：卖低价 Call + 买高价 Call</li><li>Bear Put Spread（熊市看跌）：买高价 Put + 卖低价 Put</li></ul></li><li>适用场景：预期股价涨幅或跌幅有限，控制成本和风险</li><li>最大盈利：行权价差 - 净权利金成本</li><li>最大亏损：净权利金成本</li><li>特点：通过卖出期权对冲买入成本，盈亏均有上限</li></ul><h3 id="collar-领式策略" tabindex="-1">Collar（领式策略） <a class="header-anchor" href="#collar-领式策略" aria-label="Permalink to &quot;Collar（领式策略）&quot;">​</a></h3><ul><li>构成：持有标的股票 + 买入看跌期权 + 卖出看涨期权</li><li>适用场景：持有优质股票但担忧短期下跌，寻求风险保护同时限制上涨收益</li><li>最大盈利：卖出 Call 行权价处封顶</li><li>最大亏损：买入 Put 行权价处托底</li><li>特点：用卖 Call 收入部分抵消买 Put 成本，平衡保护成本</li></ul><h3 id="straddle-跨式策略" tabindex="-1">Straddle（跨式策略） <a class="header-anchor" href="#straddle-跨式策略" aria-label="Permalink to &quot;Straddle（跨式策略）&quot;">​</a></h3><ul><li>构成：买入相同标的、相同到期日、相同行权价的看涨期权和看跌期权</li><li>适用场景：预期标的价格大幅波动但方向不确定（如财报发布、重大事件）</li><li>最大盈利：无上限</li><li>最大亏损：两张期权权利金总和</li><li>特点：捕捉任何方向的大幅波动，成本较高</li></ul><h3 id="strangle-宽跨式策略" tabindex="-1">Strangle（宽跨式策略） <a class="header-anchor" href="#strangle-宽跨式策略" aria-label="Permalink to &quot;Strangle（宽跨式策略）&quot;">​</a></h3><ul><li>构成：买入相同标的、相同到期日但不同行权价的虚值看涨期权和虚值看跌期权</li><li>适用场景：预期标的价格大幅波动但方向不确定，希望降低成本</li><li>最大盈利：无上限</li><li>最大亏损：两张期权权利金总和</li><li>特点：选择虚值期权降低成本，但需要更大幅度波动才能盈利</li></ul><hr><h2 id="策略对比" tabindex="-1">策略对比 <a class="header-anchor" href="#策略对比" aria-label="Permalink to &quot;策略对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>策略</th><th>类型</th><th>方向判断</th><th>最大盈利</th><th>最大亏损</th></tr></thead><tbody><tr><td>Covered Call</td><td>保守策略</td><td>中性偏多</td><td>有限</td><td>较大</td></tr><tr><td>Vertical Spread</td><td>方向策略</td><td>看涨或看跌</td><td>有限</td><td>有限</td></tr><tr><td>Collar</td><td>保护策略</td><td>中性</td><td>有限</td><td>有限</td></tr><tr><td>Straddle</td><td>波动策略</td><td>无方向</td><td>无限</td><td>有限</td></tr><tr><td>Strangle</td><td>波动策略</td><td>无方向</td><td>无限</td><td>有限</td></tr></tbody></table><h2 id="借方与贷方" tabindex="-1">借方与贷方 <a class="header-anchor" href="#借方与贷方" aria-label="Permalink to &quot;借方与贷方&quot;">​</a></h2><ul><li>借方策略：作为权利方，需付出权利金（如牛市看涨、熊市看跌）</li><li>贷方策略：作为义务方，可收取权利金（如牛市看跌、熊市看涨）</li></ul>',37)])])}const b=a(e,[["render",i]]);export{c as __pageData,b as default};
